import { useState, useEffect, useRef } from 'react'
import * as Notifications from 'expo-notifications'
import * as Device from 'expo-device'
import { Platform } from 'react-native'

export function usePushNotifications() {
  const [expoPushToken, setExpoPushToken] = useState<string | null>(null)
  const [permission, setPermission] = useState<'granted' | 'denied' | 'undetermined'>('undetermined')
  const notificationListener = useRef<Notifications.Subscription>()

  useEffect(() => {
    registerForPushNotifications().then(token => setExpoPushToken(token ?? null))
    notificationListener.current = Notifications.addNotificationReceivedListener(notification => {
      console.log('Notification received:', notification)
    })
    return () => { notificationListener.current?.remove() }
  }, [])

  async function registerForPushNotifications() {
    if (!Device.isDevice) { console.warn('Push notifications require a physical device'); return }
    const { status: existing } = await Notifications.getPermissionsAsync()
    let finalStatus = existing
    if (existing !== 'granted') {
      const { status } = await Notifications.requestPermissionsAsync()
      finalStatus = status
    }
    setPermission(finalStatus as any)
    if (finalStatus !== 'granted') return
    if (Platform.OS === 'android') {
      await Notifications.setNotificationChannelAsync('default', {
        name: 'default', importance: Notifications.AndroidImportance.MAX,
      })
    }
    const token = (await Notifications.getExpoPushTokenAsync()).data
    return token
  }

  return { expoPushToken, permission, registerForPushNotifications }
}
